    writeln!(f, "```")?;
    writeln!(f)?;
    writeln!(f, "## Load with v11-cli")?;
    writeln!(f, "```bash")?;
    writeln!(f, "v11 encode --text 'def fibonacci(n):'")?;
    writeln!(f, "```")?;
    f.flush()?;
    Ok(())
}

