fn main() -> Result<()> {
    let args = Args::parse();

    println!("v11-build — loading config from {}", args.config.display());
    let cfg: Config = serde_json::from_reader(BufReader::new(File::open(&args.config)?))
        .with_context(|| format!("parse {}", args.config.display()))?;

    println!("\n[1/4] assembling vocabulary from sources");
    let raw = assemble(&cfg, &args)?;
    println!("  raw vocab size: {}", raw.len());

    println!("\n[2/4] finalizing pieces (plain + ▁-prefix for word-like)");
    let user_syms = finalize_pieces(raw, &cfg);
    println!("  user_syms final: {}", user_syms.len());

    println!("\n[3/4] building Vocab artefact");
    let vocab = build_vocab_artifact(user_syms);
    println!(
        "  total pieces (incl. specials + byte fallback): {}",
        vocab.len()
    );

    println!("\n[4/4] writing outputs to {}", args.output.display());
    std::fs::create_dir_all(&args.output)?;

    let bin_path = args.output.join("v11.vocab.bin");
    vocab.save(&bin_path)?;
    println!("  wrote {}", bin_path.display());

    let json_path = args.output.join("v11.vocab.json");
    vocab.save_json(&json_path)?;
    println!("  wrote {}", json_path.display());

    let syms_path = args.output.join("knowledge_vocab.txt");
    let mut f = BufWriter::new(File::create(&syms_path)?);
    for p in &vocab.pieces {
        writeln!(f, "{}", p.text)?;
    }
    f.flush()?;
    println!("  wrote {}", syms_path.display());

    let hf_path = args.output.join("tokenizer.json");
    write_hf_tokenizer_json(&vocab, &hf_path)?;
    println!("  wrote {}", hf_path.display());

    write_tokenizer_config(&args.output.join("tokenizer_config.json"))?;
    write_special_tokens_map(&args.output.join("special_tokens_map.json"))?;
    write_model_card(&args.output.join("README.md"), &vocab)?;

    println!(
        "\nv11 build complete: {} pieces @ {}",
        vocab.len(),
        args.output.display()
    );
    if let Some(target) = cfg.vocab_size {
        println!("  target vocab_size was: {target}");
    }
    Ok(())
}

//! Pre-tokenization — transforms raw input text into a stream of
//! "pieces to be vocab-matched".
//!
//! v11 inherits the SentencePiece convention: a leading space is
//! rewritten as `▁` (U+2581) and whitespace boundaries become explicit
//! word-start markers. This lets the vocab carry both `▁def` (function
//! definition at a word boundary in Python) and `def` (substring match
//! inside e.g. `undef`) as distinct tokens.
//!
//! The output of pre-tokenization is the exact byte sequence that the
//! longest-match tokenizer will scan over.

use crate::WORD_START;

/// Replace ASCII whitespace runs with `▁`. The first character of the
/// result is always `▁` (acts as a BOS marker for longest-match).
pub fn metaspace(input: &str) -> String {
    let mut out = String::with_capacity(input.len() + 4);
    let mut prev_space = true; // treat start-of-text as "after a space"
    for ch in input.chars() {
        if ch.is_ascii_whitespace() {
            prev_space = true;
            continue;
        }
        if prev_space {
            out.push(WORD_START);
            prev_space = false;
        }
        out.push(ch);
    }
    out
}

/// Reverse the metaspace transform for decoding.
pub fn reverse_metaspace(input: &str) -> String {
    let mut out = String::with_capacity(input.len());
    let mut at_start = true;
    for ch in input.chars() {
        if ch == WORD_START {
            if !at_start {
                out.push(' ');
            }
            at_start = false;
            continue;
        }
        out.push(ch);
        at_start = false;
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn forward_and_reverse() {
        let cases = [
            "hello world",
            "def fibonacci(n):",
            "  leading spaces",
            "The capital of France is Paris",
        ];
        for s in cases {
            let meta = metaspace(s);
            let back = reverse_metaspace(&meta);
            // Trim because metaspace collapses leading whitespace
            assert_eq!(
                back.trim_start(),
                s.trim_start(),
                "roundtrip failed for {s:?}: meta={meta:?} back={back:?}"
            );
        }
    }

    #[test]
    fn starts_with_marker() {
        assert!(metaspace("hello").starts_with(WORD_START));
        assert!(metaspace("a b c").starts_with(WORD_START));
    }
}

"""Text normalisation profiles for raw triples.

Two profiles:

* ``strict`` — syntax band. Lowercase, allow letters/spaces/hyphens/apostrophes
  only. No digits. Drop self-loops. Used for WordNet, morphology, framenet, etc.
* ``permissive`` — knowledge band. Lowercase, allow letters/digits/spaces and
  a modest set of punctuation. Preserves things like "http 200", "utf-8",
  "cve-2024-1234" that matter for standards/errors/stackoverflow.

Pick a profile per dataset via the extractor's ``layer_band`` (strict for
syntax, permissive for knowledge) or override via runner config.
"""

from __future__ import annotations

from .base import RawTriple


_STRICT_ALLOWED = {" ", "-", "'"}
_PERMISSIVE_ALLOWED = {" ", "-", "'", ".", "_", "/", "+", ":", ","}


def _clean(text: str, allowed: set[str], allow_digits: bool) -> str | None:
    if not text:
        return None
    text = text.replace("_", " ") if "_" not in allowed else text
    text = text.strip().lower()
    if not text:
        return None
    for ch in text:
        if ch.isalpha():
            continue
        if allow_digits and ch.isdigit():
            continue
        if ch in allowed:
            continue
        return None
    return text


def clean_strict(text: str) -> str | None:
    return _clean(text, _STRICT_ALLOWED, allow_digits=False)


def clean_permissive(text: str) -> str | None:
    return _clean(text, _PERMISSIVE_ALLOWED, allow_digits=True)


class Normaliser:
    """Dispatches to a profile based on triple.layer_band unless forced."""

    def __init__(self, profile: str | None = None):
        self.forced_profile = profile  # None | "strict" | "permissive"

    def _profile_for(self, t: RawTriple) -> str:
        if self.forced_profile:
            return self.forced_profile
        return "strict" if t.layer_band == "syntax" else "permissive"

    def normalise(self, t: RawTriple) -> RawTriple | None:
        profile = self._profile_for(t)
        clean = clean_strict if profile == "strict" else clean_permissive
        s = clean(t.subject)
        o = clean(t.object)
        if s is None or o is None:
            return None
        if s == o:
            return None
        return RawTriple(
            subject=s,
            object=o,
            relation=t.relation,
            confidence=t.confidence,
            provenance=t.provenance,
            source=t.source,
            layer_band=t.layer_band,
        )

