import { useState, useEffect, useCallback } from "react";

interface Props {
    userId: string;
    onSave?: (user: User) => void;
}

export function UserProfile({ userId, onSave }: Props) {
    const [user, setUser] = useState<User | null>(null);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        async function load() {
            try {
                const response = await fetch(`/api/users/${userId}`);
                if (!response.ok) {
                    throw new Error(`HTTP ${response.status}`);
                }
                const data: User = await response.json();
                setUser(data);
            } catch (err) {
                setError(err instanceof Error ? err.message : "unknown error");
            } finally {
                setLoading(false);
            }
        }
        load();
    }, [userId]);

    const handleSave = useCallback(async () => {
        if (!user) return;
        await fetch(`/api/users/${userId}`, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(user),
        });
        onSave?.(user);
    }, [user, userId, onSave]);

    if (loading) return <div>Loading...</div>;
    if (error) return <div>Error: {error}</div>;
    if (!user) return null;

    return (
        <div className="user-profile">
            <h1>{user.name}</h1>
            <p>Email: {user.email}</p>
            <button onClick={handleSave}>Save</button>
        </div>
    );
}

package main

import (
    "fmt"
    "sync"
)

type Result struct {
    Index int
    Value int
}

func worker(id int, jobs <-chan int, results chan<- Result, wg *sync.WaitGroup) {
    defer wg.Done()
    for job := range jobs {
        results <- Result{Index: id, Value: job * job}
    }
}

func main() {
    jobs := make(chan int, 100)
    results := make(chan Result, 100)
    var wg sync.WaitGroup

    for w := 1; w <= 3; w++ {
        wg.Add(1)
        go worker(w, jobs, results, &wg)
    }

    for j := 1; j <= 10; j++ {
        jobs <- j
    }
    close(jobs)

    go func() {
        wg.Wait()
        close(results)
    }()

    for r := range results {
        fmt.Printf("worker %d: %d\n", r.Index, r.Value)
    }
}

"""Parses tree-sitter grammars from raw_dir and yields structural triples.

Per language, emits:

* ``keyword_begins`` — alphabetic STRING terminal appearing in a rule body
* ``contains``       — parent construct to allowed child node type
* ``is_a``           — subtype to supertype (abstract categories)
* ``followed_by``    — adjacent members inside a SEQ
* ``delimiter_role`` — punctuation/operator role within a construct

All subjects and objects representing language-scoped symbols are prefixed
``<lang>/...`` so triples from different languages don't collide. Cross-
language analysis (universal keywords, Jaccard language families) is out
of scope for this extractor and belongs downstream.
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any, Iterator

from ...base import BaseExtractor, DatasetMeta, RawTriple
from ...paths import default_raw_dir
from .model import META, TreeSitterLanguage, TreeSitterRawLayout, languages_for_tier


def _walk_rule(node: Any, visit) -> None:
    if not isinstance(node, dict):
        return
    visit(node)
    t = node.get("type")
    if t in ("SEQ", "CHOICE"):
        for m in node.get("members", []):
            _walk_rule(m, visit)
    elif t in (
        "REPEAT", "REPEAT1", "PREC", "PREC_LEFT", "PREC_RIGHT", "PREC_DYNAMIC",
        "FIELD", "ALIAS", "IMMEDIATE_TOKEN", "TOKEN",
    ):
        _walk_rule(node.get("content"), visit)


def _member_label(m: Any) -> str | None:
    if not isinstance(m, dict):
        return None
    t = m.get("type")
    if t == "STRING":
        return m.get("value")
    if t == "SYMBOL":
        return m.get("name")
    if t in ("FIELD", "ALIAS", "PREC", "PREC_LEFT", "PREC_RIGHT", "IMMEDIATE_TOKEN", "TOKEN"):
        return _member_label(m.get("content"))
    return None


def _is_keyword(value: str) -> bool:
    return bool(value) and value.isalpha() and len(value) <= 20


def _extract_from_node_types(
    node_types: list,
) -> tuple[list[tuple[str, str]], list[tuple[str, str]], list[tuple[str, str]]]:
    """Return (parent_child, field_pairs, supertype_pairs)."""
    parent_child: list[tuple[str, str]] = []
    field_pairs: list[tuple[str, str]] = []
    supertypes: list[tuple[str, str]] = []

    for node in node_types:
        if not isinstance(node, dict):
            continue
        name = node.get("type")
        if not name:
            continue

        for sub in node.get("subtypes") or []:
            st = sub.get("type")
            if st:
                supertypes.append((st, name))

        for field_name, field_info in (node.get("fields") or {}).items():
            for allowed in (field_info or {}).get("types") or []:
                at = allowed.get("type")
                if at:
                    field_pairs.append((f"{name}.{field_name}", at))

        children = node.get("children")
        if isinstance(children, dict):
            for allowed in children.get("types") or []:
                at = allowed.get("type")
                if at:
                    parent_child.append((name, at))

    return parent_child, field_pairs, supertypes


def _extract_from_grammar(
    grammar: dict,
) -> tuple[list[tuple[str, str]], list[tuple[str, str]], list[tuple[str, str]]]:
    """Return (keyword_pairs, sequence_pairs, delimiter_pairs)."""
    rules = grammar.get("rules") or {}
    keywords: list[tuple[str, str]] = []
    sequences: list[tuple[str, str]] = []
    delimiters: list[tuple[str, str]] = []

    DELIM_OPENS = {"(", "[", "{", "<"}
    DELIM_CLOSES = {")", "]", "}", ">"}

    for rule_name, rule_body in rules.items():
        skip_keywords = rule_name.startswith("_")

        def visit(n: dict, _rule_name: str = rule_name, _skip: bool = skip_keywords) -> None:
            t = n.get("type")
            if t == "SEQ":
                members = n.get("members", [])
                for a, b in zip(members, members[1:]):
                    av = _member_label(a)
                    bv = _member_label(b)
                    if av and bv:
                        sequences.append((av, bv))
            if t == "STRING":
                v = n.get("value", "")
                if v in DELIM_OPENS:
                    delimiters.append((v, f"opens:{_rule_name}"))
                elif v in DELIM_CLOSES:
                    delimiters.append((v, f"closes:{_rule_name}"))
                elif v == ",":
                    delimiters.append((v, f"separates:{_rule_name}"))
                elif v and not v.isalnum() and 1 <= len(v) <= 3 and not _skip:
                    delimiters.append((v, f"operator_in:{_rule_name}"))
                if not _skip and _is_keyword(v):
                    keywords.append((v, _rule_name))

        _walk_rule(rule_body, visit)

    return keywords, sequences, delimiters


def _read_json(path: Path) -> Any | None:
    if not path.exists():
        return None
    try:
        return json.loads(path.read_text())
    except Exception as e:
        print(f"[treesitter] unreadable {path}: {type(e).__name__}: {e}")
        return None


def _scoped(lang: str, symbol: str) -> str:
    return f"{lang}/{symbol}"


class TreeSitterExtractor(BaseExtractor):
    def meta(self) -> DatasetMeta:
        return META

    def _languages(self, config: dict) -> list[TreeSitterLanguage]:
        max_tier = config.get("max_tier")
        only = config.get("only")
        langs = languages_for_tier(max_tier)
        if only:
            names = set(only) if not isinstance(only, str) else {
                s.strip() for s in only.split(",") if s.strip()
            }
            langs = [lang for lang in langs if lang.name in names]
        return langs

    def extract(self, config: dict) -> Iterator[RawTriple]:
        base_raw = Path(config.get("raw_dir") or default_raw_dir())
        layout = TreeSitterRawLayout(raw_dir=base_raw / META.category / META.name)

        for lang in self._languages(config):
            node_types = _read_json(layout.node_types_path(lang.name))
            grammar = _read_json(layout.grammar_path(lang.name))

            if node_types is None and grammar is None:
                continue

            pc: list[tuple[str, str]] = []
            fields: list[tuple[str, str]] = []
            supertypes: list[tuple[str, str]] = []
            keywords: list[tuple[str, str]] = []
            sequences: list[tuple[str, str]] = []
            delimiters: list[tuple[str, str]] = []

            if isinstance(node_types, list):
                pc, fields, supertypes = _extract_from_node_types(node_types)
            if isinstance(grammar, dict):
                keywords, sequences, delimiters = _extract_from_grammar(grammar)

            for kw, construct in _dedupe(keywords):
                yield RawTriple(
                    subject=_scoped(lang.name, kw),
                    relation="keyword_begins",
                    object=_scoped(lang.name, construct),
                    provenance=lang.name,
                )
            for parent, child in _dedupe(pc + fields):
                yield RawTriple(
                    subject=_scoped(lang.name, parent),
                    relation="contains",
                    object=_scoped(lang.name, child),
                    provenance=lang.name,
                )
            for sub, sup in _dedupe(supertypes):
                yield RawTriple(
                    subject=_scoped(lang.name, sub),
                    relation="is_a",
                    object=_scoped(lang.name, sup),
                    provenance=lang.name,
                )
            for a, b in _dedupe(sequences):
                yield RawTriple(
                    subject=_scoped(lang.name, a),
                    relation="followed_by",
                    object=_scoped(lang.name, b),
                    provenance=lang.name,
                )
            for sym, role in _dedupe(delimiters):
                yield RawTriple(
                    subject=_scoped(lang.name, sym),
                    relation="delimiter_role",
                    object=_scoped(lang.name, role),
                    provenance=lang.name,
                )


def _dedupe(pairs: list[tuple[str, str]]) -> list[tuple[str, str]]:
    seen: set[tuple[str, str]] = set()
    out: list[tuple[str, str]] = []
    for p in pairs:
        if p in seen:
            continue
        seen.add(p)
        out.append(p)
    return out

"""Central dataset registry and tier definitions.

Each dataset has two components — a downloader and an extractor — registered
as ``"module.path:ClassName"`` strings and imported lazily. A partial install
(e.g. NLTK present but tree-sitter missing) can still `list` everything;
import errors surface only when a specific extractor is loaded.
"""

from __future__ import annotations

import importlib
from typing import Type, TypedDict

from .base import BaseDownloader, BaseExtractor


class DatasetSpec(TypedDict):
    downloader: str   # "module.path:ClassName"
    extractor: str    # "module.path:ClassName"


def _pair(pkg: str, base: str) -> DatasetSpec:
    """Build a spec for a dataset whose downloader and extractor live in
    ``knowledge_extractor.<pkg>.{downloader,extractor}`` with class names
    ``{base}Downloader`` and ``{base}Extractor``."""
    return {
        "downloader": f"knowledge_extractor.{pkg}.downloader:{base}Downloader",
        "extractor":  f"knowledge_extractor.{pkg}.extractor:{base}Extractor",
    }


DATASETS: dict[str, DatasetSpec] = {
    "linguistics/wordnet":      _pair("linguistics.wordnet", "WordNet"),
    "linguistics/morphology":   _pair("linguistics.morphology", "Morphology"),
    "linguistics/framenet":     _pair("linguistics.framenet", "FrameNet"),
    "linguistics/verbnet":      _pair("linguistics.verbnet", "VerbNet"),
    "linguistics/collocations": _pair("linguistics.collocations", "Collocations"),
    "knowledge/wikidata":       _pair("knowledge.wikidata", "Wikidata"),
    "knowledge/countries":      _pair("knowledge.countries", "Countries"),
    "knowledge/natural-earth":  _pair("knowledge.natural_earth", "NaturalEarth"),
    "knowledge/osm-gb":         _pair("knowledge.osm_gb", "OsmGb"),
    "ast/treesitter":           _pair("ast.treesitter", "TreeSitter"),
    "domain/standards":         _pair("domain.standards", "Standards"),
}


TIERS: dict[int, list[str]] = {
    1: [
        "linguistics/wordnet",
        "linguistics/morphology",
        "linguistics/framenet",
        "linguistics/verbnet",
        "linguistics/collocations",
        "ast/treesitter",
        "knowledge/wikidata",
        "knowledge/countries",
        "domain/standards",
    ],
    2: [
        "knowledge/natural-earth",
        "knowledge/osm-gb",
    ],
    3: [],
}


class ExtractorImportError(RuntimeError):
    """Raised when a dataset component's module or deps cannot be imported."""


def _load(spec: str) -> type:
    module_path, _, class_name = spec.partition(":")
    try:
        module = importlib.import_module(module_path)
    except ImportError as e:
        raise ExtractorImportError(
            f"cannot import {module_path}: {e}. "
            f"install optional deps or check pyproject.toml."
        ) from e
    try:
        return getattr(module, class_name)
    except AttributeError as e:
        raise ExtractorImportError(f"{module_path} has no class {class_name}") from e


def _get_spec(key: str) -> DatasetSpec:
    spec = DATASETS.get(key)
    if spec is None:
        known = ", ".join(sorted(DATASETS)) or "(none)"
        raise KeyError(f"unknown dataset: {key}. known: {known}")
    return spec


def load_extractor_class(key: str) -> Type[BaseExtractor]:
    return _load(_get_spec(key)["extractor"])


def load_downloader_class(key: str) -> Type[BaseDownloader]:
    return _load(_get_spec(key)["downloader"])


def instantiate_extractors(keys: list[str]) -> list[BaseExtractor]:
    return [load_extractor_class(k)() for k in keys]


def instantiate_downloaders(keys: list[str]) -> list[BaseDownloader]:
    return [load_downloader_class(k)() for k in keys]


def try_meta(key: str):
    """Return metadata for `key` or None if it can't be imported.

    Tries the extractor first (that's what users actually run); falls back to
    the downloader if the extractor can't import.
    """
    for loader in (load_extractor_class, load_downloader_class):
        try:
            return loader(key)().meta()
        except Exception:
            continue
    return None


def keys_for_category(category: str) -> list[str]:
    return [k for k in DATASETS if k.split("/", 1)[0] == category]

use std::collections::HashMap;
use std::collections::BTreeMap;

pub fn word_count(text: &str) -> HashMap<String, u32> {
    let mut counts: HashMap<String, u32> = HashMap::new();
    for word in text.split_whitespace() {
        *counts.entry(word.to_string()).or_insert(0) += 1;
    }
    counts
}

pub fn sort_by_value(map: HashMap<String, i32>) -> Vec<(String, i32)> {
    let mut pairs: Vec<(String, i32)> = map.into_iter().collect();
    pairs.sort_by(|a, b| b.1.cmp(&a.1));
    pairs
}

pub fn parse_int(s: &str) -> Result<i64, String> {
    s.parse::<i64>().map_err(|e| format!("parse error: {}", e))
}

pub fn read_lines(path: &str) -> Result<Vec<String>, std::io::Error> {
    let contents = std::fs::read_to_string(path)?;
    Ok(contents.lines().map(String::from).collect())
}

//! The v11 tokenizer runtime.
//!
//! Algorithm: a faithful port of the HuggingFace `tokenizers` crate
//! Unigram `encode_optimized` — trie-based Viterbi with shortest-first
//! prefix iteration, strict `>` score comparison (first-reacher wins on
//! ties), and an unk penalty of `min_score - 10`. This guarantees that
//! `v11-core::Tokenizer::encode` produces byte-identical ids to
//! `transformers.AutoTokenizer.from_pretrained(<artifacts dir>).encode` for
//! the same vocab.
//!
//! Pretokenization matches HF `Metaspace(prepend_scheme=always, split=true)`:
//! whitespace runs split the stream into chunks, each chunk is prefixed
//! with `▁`, and Viterbi runs per chunk.

use std::collections::HashMap;
use std::path::Path;

use crate::error::Result;
use crate::pretokenize::reverse_metaspace;
use crate::vocab::Vocab;
use crate::WORD_START;

const K_UNK_PENALTY: f32 = 10.0;

pub struct Tokenizer {
    vocab: Vocab,
    trie: Trie,
    min_score: f32,
    unk_id: u32,
}

struct Trie {
    children: Vec<HashMap<u8, u32>>,
    leaf_id: Vec<Option<u32>>,
    leaf_score: Vec<f32>,
}

impl Trie {
    fn new() -> Self {
        Self {
            children: vec![HashMap::new()],
            leaf_id: vec![None],
            leaf_score: vec![0.0],
        }
    }

    fn insert(&mut self, bytes: &[u8], id: u32, score: f32) {
        let mut node = 0usize;
        for &b in bytes {
            let next = self.children[node].get(&b).copied();
            node = match next {
                Some(n) => n as usize,
                None => {
                    let new = self.children.len();
                    self.children.push(HashMap::new());
                    self.leaf_id.push(None);
                    self.leaf_score.push(0.0);
                    self.children[node].insert(b, new as u32);
                    new
                }
            };
        }
        self.leaf_id[node] = Some(id);
        self.leaf_score[node] = score;
    }
}

#[derive(Clone, Copy)]
struct BestNode {
    starts_at: Option<u32>,
    best_score: f32,
    id: u32,
}

impl Default for BestNode {
    fn default() -> Self {
        Self {
            starts_at: None,
            best_score: 0.0,
            id: 0,
        }
    }
}

impl Tokenizer {
    pub fn from_vocab(vocab: Vocab) -> Self {
        let unk_id = vocab.special.unk_id;
        let mut trie = Trie::new();
        let mut min_score = f32::MAX;
        for p in &vocab.pieces {
            // The four control specials never segment user text.
            // Everything else — including literal `<0xNN>` pieces — goes
            // into the trie as an ordinary piece, matching HF's behavior
            // for this tokenizer.json (byte_fallback is not set, so the
            // `<0xNN>` strings are opaque literals).
            if p.id == vocab.special.pad_id
                || p.id == vocab.special.bos_id
                || p.id == vocab.special.eos_id
                || p.id == vocab.special.unk_id
            {
                continue;
            }
            trie.insert(p.text.as_bytes(), p.id, p.score);
            if p.score < min_score {
                min_score = p.score;
            }
        }
        if min_score == f32::MAX {
            min_score = 0.0;
        }
        Self {
            vocab,
            trie,
            min_score,
            unk_id,
        }
    }

    pub fn from_file<P: AsRef<Path>>(path: P) -> Result<Self> {
        Ok(Self::from_vocab(Vocab::load(path)?))
    }

    pub fn vocab(&self) -> &Vocab {
        &self.vocab
    }
    pub fn vocab_size(&self) -> usize {
        self.vocab.len()
    }

    /// Encode `text` into a sequence of token IDs. Produces the same
    /// ids as HF `transformers.AutoTokenizer` on the same tokenizer.json.
    pub fn encode(&self, text: &str) -> Vec<u32> {
        let mut out = Vec::with_capacity(text.len() / 3 + 1);
        for chunk in pretokenize_chunks(text) {
            self.encode_chunk(&chunk, &mut out);
        }
        out
    }

    /// Alias kept for callers that used the old API name.
    pub fn encode_pretokenized(&self, pre: &str) -> Vec<u32> {
        // `pre` is already metaspace-form — split on ▁ into chunks and run.
        let mut out = Vec::with_capacity(pre.len() / 3 + 1);
        let marker = WORD_START.to_string();
        for chunk in pre.split(&marker).filter(|s| !s.is_empty()) {
            let mut with_marker = String::with_capacity(chunk.len() + 3);
            with_marker.push(WORD_START);
            with_marker.push_str(chunk);
            self.encode_chunk(&with_marker, &mut out);
        }
        out
    }

    fn encode_chunk(&self, sentence: &str, out: &mut Vec<u32>) {
        let bytes = sentence.as_bytes();
        let size = bytes.len();
        if size == 0 {
            return;
        }
        let mut best = vec![BestNode::default(); size + 1];
        best[0].starts_at = Some(0);
        best[0].best_score = 0.0;

        let mut starts_at = 0usize;
        while starts_at < size {
            let mblen = utf8_char_len(bytes[starts_at]);
            // If this position was never reached, we still need to advance
            // so the backtrace can finish. Seed it with a fresh path from
            // the previous char if none exists.
            if best[starts_at].starts_at.is_none() {
                starts_at += mblen;
                continue;
            }
            let best_score_till_here = best[starts_at].best_score;
            let mut has_single_node = false;

            // common_prefix_search: walk the trie along bytes, yielding
            // matches shortest-first as we descend through leaf nodes.
            let mut node = 0u32;
            let mut i = 0usize;
            while starts_at + i < size {
                let b = bytes[starts_at + i];
                match self.trie.children[node as usize].get(&b) {
                    Some(&next) => {
                        node = next;
                        i += 1;
                        if let Some(id) = self.trie.leaf_id[node as usize] {
                            let piece_score = self.trie.leaf_score[node as usize];
                            let key_pos = starts_at + i;
                            let candidate = best_score_till_here + piece_score;
                            let target = &mut best[key_pos];
                            if target.starts_at.is_none() || candidate > target.best_score {
                                target.starts_at = Some(starts_at as u32);
                                target.best_score = candidate;
                                target.id = id;
                            }
                            if !has_single_node && i == mblen {
                                has_single_node = true;
                            }
                        }
                    }
                    None => break,
                }
            }

            if !has_single_node {
                let unk_score = self.min_score - K_UNK_PENALTY;
                let key_pos = starts_at + mblen;
                let candidate = best_score_till_here + unk_score;
                let target = &mut best[key_pos];
                if target.starts_at.is_none() || candidate > target.best_score {
                    target.starts_at = Some(starts_at as u32);
                    target.best_score = candidate;
                    target.id = self.unk_id;
                }
            }
            starts_at += mblen;
        }

        // Backtrace
        let mut ends_at = size;
        let start_len = out.len();
        while ends_at > 0 {
            let node = best[ends_at];
            let sa = match node.starts_at {
                Some(v) => v as usize,
                // Safety net: if something unreachable crept through,
                // bail with unk rather than panic.
                None => {
                    out.push(self.unk_id);
                    break;
                }
            };
            out.push(node.id);
            ends_at = sa;
        }
        out[start_len..].reverse();
    }

    /// Decode a sequence of token IDs back to text. Matches HF decoding:
    /// concatenate piece texts (including literal `<0xNN>` strings if any
    /// slipped in), then reverse-metaspace.
    pub fn decode(&self, ids: &[u32]) -> String {
        let mut bytes: Vec<u8> = Vec::new();
        for &id in ids {
            if id == self.vocab.special.pad_id
                || id == self.vocab.special.bos_id
                || id == self.vocab.special.eos_id
                || id == self.vocab.special.unk_id
            {
                continue;
            }
            if let Some(text) = self.vocab.get_text(id) {
                bytes.extend_from_slice(text.as_bytes());
            }
        }
        let s = String::from_utf8_lossy(&bytes).into_owned();
        reverse_metaspace(&s)
    }

    pub fn decode_pieces(&self, ids: &[u32]) -> Vec<String> {
        ids.iter()
            .map(|&i| self.vocab.get_text(i).unwrap_or("<unk>").to_string())
            .collect()
    }
}

fn utf8_char_len(first_byte: u8) -> usize {
    // Malformed continuation bytes (0x80-0xBF) are bucketed with ASCII at 1
    // so the outer loop still makes progress on invalid UTF-8.
    if first_byte < 0xC0 {
        1
    } else if first_byte < 0xE0 {
        2
    } else if first_byte < 0xF0 {
        3
    } else {
        4
    }
}

/// Split input into HF-Metaspace chunks: whitespace runs are delimiters,
/// each non-whitespace run becomes a chunk with a leading `▁`.
fn pretokenize_chunks(input: &str) -> Vec<String> {
    let mut chunks = Vec::new();
    let mut cur = String::new();
    let mut in_word = false;
    for ch in input.chars() {
        if ch.is_ascii_whitespace() {
            if in_word {
                chunks.push(std::mem::take(&mut cur));
                in_word = false;
            }
        } else {
            if !in_word {
                cur.push(WORD_START);
                in_word = true;
            }
            cur.push(ch);
        }
    }
    if in_word {
        chunks.push(cur);
    }
    chunks
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::vocab::{Piece, SpecialTokens};

    fn mini_vocab() -> Vocab {
        let pieces = vec![
            Piece {
                id: 0,
                text: "<pad>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 1,
                text: "<unk>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 2,
                text: "<s>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 3,
                text: "</s>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 4,
                text: "\u{2581}hello".to_string(),
                score: 0.0,
            },
            Piece {
                id: 5,
                text: "\u{2581}world".to_string(),
                score: 0.0,
            },
            Piece {
                id: 6,
                text: "!".to_string(),
                score: 0.0,
            },
        ];
        Vocab::new(pieces, SpecialTokens::default())
    }

    #[test]
    fn encode_known_words() {
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("hello world");
        assert_eq!(ids, vec![4, 5]);
    }

    #[test]
    fn encode_with_punct_chunked() {
        // "hello" and "world!" are separate chunks; within "▁world!"
        // the Viterbi path picks ▁world then !
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("hello world!");
        assert_eq!(ids, vec![4, 5, 6]);
    }

    #[test]
    fn unknown_char_becomes_unk() {
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("xy");
        // No piece covers 'x' or 'y' and no byte-fallback pieces in mini
        // vocab → every char becomes unk.
        assert!(ids.iter().all(|&i| i == 1));
    }

    #[test]
    fn decode_roundtrip_basic() {
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("hello world");
        let back = t.decode(&ids);
        assert_eq!(back.trim_start(), "hello world");
    }

    #[test]
    fn empty_input_yields_empty() {
        let t = Tokenizer::from_vocab(mini_vocab());
        assert!(t.encode("").is_empty());
        assert_eq!(t.decode(&[]), "");
    }

    #[test]
    fn multiple_whitespace_collapses() {
        let t = Tokenizer::from_vocab(mini_vocab());
        let a = t.encode("hello world");
        let b = t.encode("hello    world");
        let c = t.encode("  hello\tworld  ");
        assert_eq!(a, b);
        assert_eq!(a, c);
    }

    #[test]
    fn longest_match_beats_piecewise() {
        // With "▁hello" in vocab, "hello" encodes to the single piece,
        // not to characters.
        let t = Tokenizer::from_vocab(mini_vocab());
        assert_eq!(t.encode("hello"), vec![4]);
    }

    #[test]
    fn unicode_passes_through_as_unk() {
        // mini_vocab has no multibyte chars; they become unk (not panic).
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("α β γ");
        assert!(!ids.is_empty());
        assert!(ids.iter().all(|&i| i == 1));
    }

    #[test]
    fn tie_holds_first_reacher() {
        // Vocab has both "▁ab" and "▁a"+"b". At starts_at=0 the trie walk
        // yields "▁a" (writes position 4) then "▁ab" (writes position 5).
        // Downstream, starts_at=4 sees piece "b" which ties best[5]'s
        // existing score (0.0 == 0.0) — strict `>` means no overwrite,
        // so backtrace returns the single piece "▁ab".
        let pieces = vec![
            Piece {
                id: 0,
                text: "<pad>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 1,
                text: "<unk>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 2,
                text: "<s>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 3,
                text: "</s>".to_string(),
                score: 0.0,
            },
            Piece {
                id: 4,
                text: "\u{2581}a".to_string(),
                score: 0.0,
            },
            Piece {
                id: 5,
                text: "b".to_string(),
                score: 0.0,
            },
            Piece {
                id: 6,
                text: "\u{2581}ab".to_string(),
                score: 0.0,
            },
        ];
        let t = Tokenizer::from_vocab(Vocab::new(pieces, SpecialTokens::default()));
        let ids = t.encode("ab");
        assert_eq!(ids, vec![6]);
    }

    #[test]
    fn long_word_stays_within_capacity() {
        // No crash on a 10kB input; all 10000 'z' chars + the leading ▁
        // marker each become unk in mini vocab → 10001 ids.
        let t = Tokenizer::from_vocab(mini_vocab());
        let big: String = "z".repeat(10_000);
        let ids = t.encode(&big);
        assert_eq!(ids.len(), 10_001);
        assert!(ids.iter().all(|&i| i == 1));
    }

    #[test]
    fn special_tokens_stripped_on_decode() {
        let t = Tokenizer::from_vocab(mini_vocab());
        // pad=0, bos=2, eos=3 — injecting them should be silent.
        let back = t.decode(&[2, 4, 5, 3]);
        assert_eq!(back.trim_start(), "hello world");
    }

    #[test]
    fn decode_pieces_preserves_markers() {
        let t = Tokenizer::from_vocab(mini_vocab());
        let ids = t.encode("hello world!");
        let pieces = t.decode_pieces(&ids);
        assert_eq!(pieces, vec!["▁hello", "▁world", "!"]);
    }
}

